def main():
    conn = sqlite3.connect(DB_PATH)
    conn.execute("PRAGMA journal_mode=WAL")

    updated = 0
    skipped = 0
    not_found = 0

    for slug, definition_long in DEFINITIONS:
        # Check if row exists and definition_long is NULL
        row = conn.execute(
            "SELECT definition_long FROM dictionary_terms WHERE slug = ?",
            (slug,)
        ).fetchone()

        if row is None:
            print(f"  NOT FOUND: {slug}")
            not_found += 1
            continue

        if row[0] is not None:
            print(f"  SKIPPED (already set): {slug}")
            skipped += 1
            continue

        conn.execute(
            "UPDATE dictionary_terms SET definition_long = ? WHERE slug = ?",
            (definition_long, slug)
        )
        updated += 1
        print(f"  UPDATED: {slug}")

    conn.commit()

    # Verify
    total_null = conn.execute(
        "SELECT COUNT(*) FROM dictionary_terms WHERE definition_long IS NULL"
    ).fetchone()[0]
    total = conn.execute("SELECT COUNT(*) FROM dictionary_terms").fetchone()[0]

    conn.close()

    print(f"\n--- Results ---")
    print(f"Updated: {updated}")
    print(f"Skipped (already set): {skipped}")
    print(f"Not found: {not_found}")
    print(f"Remaining NULL: {total_null}/{total}")


if __name__ == "__main__":
    main()
